import{_ as a,o as n,c as t,O as s}from"./chunks/framework.0d5b6918.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/source-delivery-boundaries.md","filePath":"en/materials/source-delivery-boundaries.md","lastUpdated":1776344074000}'),r={name:"en/materials/source-delivery-boundaries.md"};function i(d,e,o,l,c,p){return n(),t("div",null,e[0]||(e[0]=[s('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Delivery Scope</p><h1>Source Delivery and Licensing Boundary</h1><div class="brand-hero__panel"><span class="brand-pill">Client Delivery Scope</span><strong>If you are evaluating deployment mode, future maintenance, or control of source code, this page explains the difference between standard delivery, private deployment, and source-code licensing.</strong><p>The point is to make delivery scope, licensing mode, and maintenance responsibility clear before pricing so both sides do not carry different assumptions.</p></div><p class="brand-lead"> There are usually three modes right now: <strong>standard delivery, private deployment, and source-code licensing or buyout</strong>. Whether source code is included depends not only on whether deployment is independent, but also on the licensing scope and future maintenance arrangement agreed by both sides. </p><div class="brand-chip-list"><span class="brand-chip">standard delivery</span><span class="brand-chip">private deployment</span><span class="brand-chip">source-code licensing</span><span class="brand-chip">explicit contract wording</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./service-packages.html">View service packages and kickoff</a><a class="cta-button" href="../product/deliverables.html">View customer delivery docs &amp; entry points</a><a class="cta-button" href="../product/customer-flow.html">View Customer Delivery &amp; Usage</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // DELIVERY SCOPE</span><span>MAT 10</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">standard</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">usable_delivery</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">private</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">independent_environment</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">source</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">licensed_separately</span></span></div><div class="matrix-panel__callout">CLARIFY SCOPE BEFORE DELIVERY</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">clear scope</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery + license</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">project discussion</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Mode 01</p><h2>Standard delivery</h2><p>This mode is better when the first priority is whether the system can run stably and pass formal acceptance. Full-repository source transfer is not included by default.</p></article><article class="brand-card"><p class="brand-kicker">Mode 02</p><h2>Private deployment</h2><p>This mode is better when the customer needs independent servers, databases, domains, and runtime environments, but the source-code scope still has to be agreed separately.</p></article><article class="brand-card"><p class="brand-kicker">Mode 03</p><h2>Source-code licensing or buyout</h2><p>This mode is better when the customer clearly needs future self-maintenance, second-stage development, or stronger control rights, and it should be handled as a separate licensing mode.</p></article></section><section class="brand-card"><p class="brand-kicker">Pricing Boundary</p><h2>The boundary between the three delivery and licensing modes</h2><table class="cooperation-start-table"><thead><tr><th>Mode</th><th>Default delivery contents</th><th>Source-code status</th><th>Best-fit scenario</th></tr></thead><tbody><tr><td>Standard delivery</td><td>Deployed system, access entry points, accounts, instruction documents, result entries, and necessary configuration handover</td><td>Full-repository source code is not transferred by default</td><td>Best when the first priority is runnable output, formal acceptance, and stable use</td></tr><tr><td>Private deployment</td><td>Deployment in the customer&#39;s independent environment, deployment manual, parameter list, ops handover, and acceptance support</td><td>The scope of source code has to be agreed separately</td><td>Best when the customer needs an independent server, independent deployment, intranet operation, or a stronger boundary</td></tr><tr><td>Source-code licensing / buyout</td><td>Code within the project scope, deployment scripts, necessary instructions, and agreed licensing boundary</td><td>Licensed separately and quoted separately</td><td>Best when the customer explicitly needs source-code control rights and is willing to bear the higher cost</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Quick Summary</p><h2>Read these four sentences first</h2><ul class="brand-list"><li>Standard delivery defaults to runnable results, accounts, documents, and delivery explanation.</li><li>Private deployment defaults to independent environments, deployment handover, and acceptance support.</li><li>Independent deployment does not automatically mean a full-repository source-code buyout.</li><li>If source transfer, second-stage development, or stronger control is needed, that is stated separately in pricing and contract wording.</li></ul></article><article class="brand-card"><p class="brand-kicker">Clarification</p><h2>Why independent deployment does not automatically equal a source-code buyout</h2><ul class="brand-list"><li>Many projects mainly need something that is runnable, acceptable, and stable in long-term use, not immediate takeover of the whole codebase.</li><li>Platform projects usually include a general foundation, project-scope implementation, and delivery instructions at the same time, so the source boundary has to be drawn explicitly by agreement.</li><li>If you need future self-maintenance, second-stage development, or stronger control, the mode can switch into source-code licensing or buyout.</li><li>That makes maintenance responsibility, upgrade mode, and fee boundary clearer for both sides.</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Contract Wording</p><h2>Three paragraphs that can be written directly into a proposal or contract</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>1. Standard-delivery wording</h3><p>This quotation includes feature implementation within the project scope, deployment landing, account and documentation handover, and problem fixing plus acceptance support within the agreed period. It does not include full-repository source transfer or permanent buyout licensing by default.</p></article><article class="brand-card brand-card--nested"><h3>2. Private-deployment wording</h3><p>This delivery is executed on the customer&#39;s independent servers, database, and domain. Deliverables include the runtime environment, deployment manual, parameter list, and acceptance support. If source transfer or a stronger licensing boundary is needed, that should be agreed separately on top of private deployment.</p></article><article class="brand-card brand-card--nested"><h3>3. Source-code licensing wording</h3><p>If project-scope source transfer, future self-maintenance, or stronger control is required, this should be quoted separately under a source-code licensing or buyout mode. The quotation will be materially higher than ordinary implementation and deployment delivery and should not be mixed into the standard delivery package.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Project Scope</p><h2>If you explicitly need source code, confirm these four questions first</h2><ol class="brand-list"><li>Whether the transfer is the full repository or only the code inside this project scope.</li><li>Whether future self-modification and redistribution rights are included.</li><li>After source delivery, who still takes responsibility for later maintenance.</li><li>Whether the general foundation, other-customer content, and internal documents are excluded from this delivery scope.</li></ol></section></div>',1)]))}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
